import functools, time, logging
def timing(fn):
    @functools.wraps(fn)
    def wrapper(*args, **kwargs):
        t = time.perf_counter()
        try: return fn(*args, **kwargs)
        finally: logging.info('%s took %.3fs', fn.__name__, time.perf_counter()-t)
    return wrapper
