def retry(times=3):
    def deco(fn):
        @functools.wraps(fn)
        def wrapper(*a, **kw):
            for i in range(times):
                try: return fn(*a, **kw)
                except Exception:
                    if i == times-1: raise
        return wrapper
    return deco

@retry(times=5)
def embed(text): ...
